<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Customers</h1><p class="text-muted mb-0">Customer and property records.</p></div><a class="btn btn-primary" href="/portal/customers/create"><i class="fa-solid fa-plus"></i> New Customer</a></div>
<form class="card card-body mb-3" method="get"><div class="input-group"><input class="form-control" name="q" value="<?=e($q)?>" placeholder="Search name, email, or phone"><button class="btn btn-outline-primary">Search</button></div></form>
<div class="card"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Customer</th><th>Type</th><th>Contact</th><th>Properties</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($customers as $c):?><tr><td><strong><?=e($c['display_name'])?></strong><br><small class="text-muted"><?=e($c['contact_name'])?></small></td><td><?=e(ucfirst($c['customer_type']))?></td><td><?=e($c['phone'])?><br><?=e($c['email'])?></td><td><?=e($c['property_count'])?></td><td><span class="badge text-bg-success"><?=e($c['status'])?></span></td><td class="text-end"><a class="btn btn-sm btn-outline-primary" href="/portal/customers/<?=$c['id']?>">Open</a></td></tr><?php endforeach; if(!$customers):?><tr><td colspan="6" class="text-center py-5 text-muted">No customers found.</td></tr><?php endif?></tbody></table></div></div>
